// Branch A: Etsy Marketplace Intelligence (Claude + web search)
const etsyItems = $('Claude — Etsy Marketplace Intelligence').all();
const etsyOpportunities = [];
for (const item of etsyItems) {
  const content = item.json.content || [];
  const textBlocks = content.filter(b => b.type === 'text');
  for (const block of textBlocks) {
    const raw = block.text || '';
    const firstBracket = raw.indexOf('[');
    const lastBracket  = raw.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket !== -1) {
      try {
        const parsed = JSON.parse(raw.substring(firstBracket, lastBracket + 1));
        if (Array.isArray(parsed)) {
          parsed.forEach(o => etsyOpportunities.push({ source: 'etsy_web_search', ...o }));
          break;
        }
      } catch(e) { /* skip */ }
    }
  }
}

// Branch B: KDP + Google Trends + Reddit Intelligence (Claude + web search)
const kdpItems = $('Claude — KDP/Trends/Reddit Intelligence').all();
const kdpOpportunities = [];
for (const item of kdpItems) {
  const content = item.json.content || [];
  const textBlocks = content.filter(b => b.type === 'text');
  for (const block of textBlocks) {
    const raw = block.text || '';
    const firstBracket = raw.indexOf('[');
    const lastBracket  = raw.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket !== -1) {
      try {
        const parsed = JSON.parse(raw.substring(firstBracket, lastBracket + 1));
        if (Array.isArray(parsed)) {
          parsed.forEach(o => kdpOpportunities.push({ source: 'kdp_trends_reddit', ...o }));
          break;
        }
      } catch(e) { /* skip */ }
    }
  }
}

return [{ json: {
  etsyOpportunities,
  kdpOpportunities,
  totalEtsy: etsyOpportunities.length,
  totalKDP: kdpOpportunities.length
} }];

const content = $json.content || [];
const textBlock = content.find(b => b.type === 'text');
const raw = textBlock ? textBlock.text : '';

const firstBracket = raw.indexOf('[');
const lastBracket  = raw.lastIndexOf(']');

let opportunities = [];
if (firstBracket !== -1 && lastBracket !== -1) {
  try {
    opportunities = JSON.parse(raw.substring(firstBracket, lastBracket + 1));
  } catch(e) {
    opportunities = [];
  }
}

opportunities = opportunities.filter(o => o.score >= 6.5 && o.title && o.niche);

if (opportunities.length === 0) {
  return [{ json: { title: '_no_results', niche: 'none', score: 0, status: 'pending', skip: true } }];
}

return opportunities.map(o => ({ json: o }));

// Supabase POST returns an array even for single inserts
const row = Array.isArray($json) ? ($json[0] || $json) : $json;
return [{ json: row }];
